import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import SortableTable from '../../components/SortableTable';

interface Promotor {
  id: number;
  nome: string;
  email: string;
  telefone: string;
}

const PromotoresList: React.FC = () => {
  const [promotores, setPromotores] = useState<Promotor[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [filtro, setFiltro] = useState<string>('');

  useEffect(() => {
    const fetchPromotores = async () => {
      try {
        setLoading(true);
        const response = await axios.get<Promotor[]>('/api/promotores');
        setPromotores(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar promotores. Por favor, tente novamente.');
        console.error('Erro ao buscar promotores:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchPromotores();
  }, []);

  const handleDelete = async (id: number, nome: string) => {
    if (!window.confirm(`Tem certeza que deseja excluir o promotor "${nome}"?`)) {
      return;
    }

    try {
      await axios.delete(`/api/promotores/${id}`);
      setPromotores(promotores.filter(promotor => promotor.id !== id));
    } catch (err) {
      setError('Erro ao excluir promotor. Por favor, tente novamente.');
      console.error('Erro ao excluir promotor:', err);
    }
  };

  const promotoresFiltrados = promotores.filter(promotor => {
    const termoBusca = filtro.toLowerCase();
    return (
      (promotor.nome && promotor.nome.toLowerCase().includes(termoBusca)) ||
      (promotor.email && promotor.email.toLowerCase().includes(termoBusca))
    );
  });

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Erro!</strong>
        <span className="block sm:inline"> {error}</span>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Promotores</h1>
        <Link 
          to="/promotores/novo" 
          className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded"
        >
          Novo Promotor
        </Link>
      </div>

      <div className="mb-6">
        <input
          type="text"
          placeholder="Buscar por nome ou email..."
          className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          value={filtro}
          onChange={(e) => setFiltro(e.target.value)}
        />
      </div>

      {promotoresFiltrados.length === 0 ? (
        <div className="bg-gray-50 p-6 rounded-lg text-center">
          <p className="text-gray-600">Nenhum promotor encontrado.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nome</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Telefone</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {promotoresFiltrados.map((promotor) => (
                <tr key={promotor.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{promotor.nome}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{promotor.email}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{promotor.telefone}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      <Link to={`/promotores/${promotor.id}`} className="text-blue-600 hover:text-blue-900">
                        Detalhes
                      </Link>
                      <Link to={`/promotores/editar/${promotor.id}`} className="text-indigo-600 hover:text-indigo-900">
                        Editar
                      </Link>
                      <button
                        onClick={() => handleDelete(promotor.id, promotor.nome)}
                        className="text-red-600 hover:text-red-900"
                      >
                        Excluir
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default PromotoresList;
